# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import os
import json
import numpy as np
from flask import Flask, request, jsonify
from collections import Counter, defaultdict
from datetime import datetime
import pickle
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import threading
import hashlib

app = Flask(__name__)

class CrowdsourcedLabelingSystem:
    def __init__(self, data_dir='labeled_data'):
        self.data_dir = data_dir
        self.labels_file = os.path.join(data_dir, 'labels.json')
        self.aggregated_file = os.path.join(data_dir, 'aggregated.json')
        self.model_file = os.path.join(data_dir, 'model.pkl')
        self.encoder_file = os.path.join(data_dir, 'encoder.pkl')
        
        os.makedirs(data_dir, exist_ok=True)
        
        self.labels = self._load_labels()
        self.aggregated_labels = self._load_aggregated()
        self.model = None
        self.label_encoder = LabelEncoder()
        self.lock = threading.Lock()
        
    def _load_labels(self):
        if os.path.exists(self.labels_file):
            with open(self.labels_file, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_labels(self):
        with open(self.labels_file, 'w') as f:
            json.dump(self.labels, f, indent=2)
    
    def _load_aggregated(self):
        if os.path.exists(self.aggregated_file):
            with open(self.aggregated_file, 'r') as f:
                return json.load(f)
        return {}
    
    def _save_aggregated(self):
        with open(self.aggregated_file, 'w') as f:
            json.dump(self.aggregated_labels, f, indent=2)
    
    def add_label(self, image_id, annotator_id, label, confidence=1.0):
        with self.lock:
            if image_id not in self.labels:
                self.labels[image_id] = []
            
            annotation = {
                'annotator_id': annotator_id,
                'label': label,
                'confidence': confidence,
                'timestamp': datetime.now().isoformat()
            }
            
            self.labels[image_id].append(annotation)
            self._save_labels()
            
            self._aggregate_labels_for_image(image_id)
            
            return True
    
    def _aggregate_labels_for_image(self, image_id):
        if image_id not in self.labels or len(self.labels[image_id]) == 0:
            return None
        
        annotations = self.labels[image_id]
        label_votes = []
        
        for ann in annotations:
            label_votes.append(ann['label'])
        
        vote_counts = Counter(label_votes)
        majority_label = vote_counts.most_common(1)[0][0]
        total_votes = len(label_votes)
        majority_count = vote_counts[majority_label]
        
        self.aggregated_labels[image_id] = {
            'label': majority_label,
            'vote_count': majority_count,
            'total_votes': total_votes,
            'confidence': majority_count / total_votes,
            'all_votes': dict(vote_counts),
            'updated_at': datetime.now().isoformat()
        }
        
        self._save_aggregated()
        
        return self.aggregated_labels[image_id]
    
    def aggregate_all_labels(self):
        with self.lock:
            for image_id in self.labels.keys():
                self._aggregate_labels_for_image(image_id)
            return len(self.aggregated_labels)
    
    def get_aggregated_label(self, image_id):
        return self.aggregated_labels.get(image_id)
    
    def get_all_annotations(self, image_id):
        return self.labels.get(image_id, [])
    
    def get_statistics(self):
        total_images = len(self.labels)
        total_annotations = sum(len(anns) for anns in self.labels.values())
        aggregated_count = len(self.aggregated_labels)
        
        annotators = set()
        for anns in self.labels.values():
            for ann in anns:
                annotators.add(ann['annotator_id'])
        
        label_distribution = defaultdict(int)
        for agg in self.aggregated_labels.values():
            label_distribution[agg['label']] += 1
        
        return {
            'total_images': total_images,
            'total_annotations': total_annotations,
            'aggregated_labels': aggregated_count,
            'unique_annotators': len(annotators),
            'label_distribution': dict(label_distribution)
        }
    
    def train_model(self, features_dict):
        with self.lock:
            if len(self.aggregated_labels) == 0:
                return {'error': 'No aggregated labels available for training'}
            
            X = []
            y = []
            
            for image_id, agg_data in self.aggregated_labels.items():
                if image_id in features_dict:
                    X.append(features_dict[image_id])
                    y.append(agg_data['label'])
            
            if len(X) == 0:
                return {'error': 'No features available for training'}
            
            X = np.array(X)
            y = np.array(y)
            
            y_encoded = self.label_encoder.fit_transform(y)
            
            self.model = RandomForestClassifier(n_estimators=100, random_state=42)
            self.model.fit(X, y_encoded)
            
            with open(self.model_file, 'wb') as f:
                pickle.dump(self.model, f)
            
            with open(self.encoder_file, 'wb') as f:
                pickle.dump(self.label_encoder, f)
            
            return {
                'status': 'success',
                'training_samples': len(X),
                'unique_labels': len(self.label_encoder.classes_),
                'labels': self.label_encoder.classes_.tolist()
            }
    
    def predict(self, features):
        if self.model is None:
            if os.path.exists(self.model_file):
                with open(self.model_file, 'rb') as f:
                    self.model = pickle.load(f)
                with open(self.encoder_file, 'rb') as f:
                    self.label_encoder = pickle.load(f)
            else:
                return None
        
        features = np.array(features).reshape(1, -1)
        prediction_encoded = self.model.predict(features)
        prediction = self.label_encoder.inverse_transform(prediction_encoded)
        
        probabilities = self.model.predict_proba(features)[0]
        
        return {
            'prediction': prediction[0],
            'confidence': float(max(probabilities)),
            'probabilities': {label: float(prob) for label, prob in zip(self.label_encoder.classes_, probabilities)}
        }

labeling_system = CrowdsourcedLabelingSystem()

@app.route('/api/label', methods=['POST'])
def add_label():
    data = request.json
    
    if not data or 'image_id' not in data or 'annotator_id' not in data or 'label' not in data:
        return jsonify({'error': 'Missing required fields: image_id, annotator_id, label'}), 400
    
    image_id = data['image_id']
    annotator_id = data['annotator_id']
    label = data['label']
    confidence = data.get('confidence', 1.0)
    
    success = labeling_system.add_label(image_id, annotator_id, label, confidence)
    
    aggregated = labeling_system.get_aggregated_label(image_id)
    
    return jsonify({
        'status': 'success',
        'image_id': image_id,
        'aggregated_label': aggregated
    }), 201

@app.route('/api/labels/<image_id>', methods=['GET'])
def get_labels(image_id):
    annotations = labeling_system.get_all_annotations(image_id)
    aggregated = labeling_system.get_aggregated_label(image_id)
    
    return jsonify({
        'image_id': image_id,
        'annotations': annotations,
        'aggregated': aggregated
    })

@app.route('/api/aggregated/<image_id>', methods=['GET'])
def get_aggregated(image_id):
    aggregated = labeling_system.get_aggregated_label(image_id)
    
    if aggregated is None:
        return jsonify({'error': 'No aggregated label found for this image'}), 404
    
    return jsonify({
        'image_id': image_id,
        'aggregated': aggregated
    })

@app.route('/api/aggregate', methods=['POST'])
def aggregate_all():
    count = labeling_system.aggregate_all_labels()
    
    return jsonify({
        'status': 'success',
        'aggregated_count': count
    })

@app.route('/api/statistics', methods=['GET'])
def get_statistics():
    stats = labeling_system.get_statistics()
    return jsonify(stats)

@app.route('/api/train', methods=['POST'])
def train_model():
    data = request.json
    
    if not data or 'features' not in data:
        return jsonify({'error': 'Missing features dictionary'}), 400
    
    features_dict = data['features']
    
    result = labeling_system.train_model(features_dict)
    
    if 'error' in result:
        return jsonify(result), 400
    
    return jsonify(result)

@app.route('/api/predict', methods=['POST'])
def predict():
    data = request.json
    
    if not data or 'features' not in data:
        return jsonify({'error': 'Missing features array'}), 400
    
    features = data['features']
    
    result = labeling_system.predict(features)
    
    if result is None:
        return jsonify({'error': 'Model not trained yet'}), 400
    
    return jsonify(result)

@app.route('/api/batch_labels', methods=['POST'])
def batch_add_labels():
    data = request.json
    
    if not data or 'labels' not in data:
        return jsonify({'error': 'Missing labels array'}), 400
    
    results = []
    
    for label_data in data['labels']:
        if 'image_id' not in label_data or 'annotator_id' not in label_data or 'label' not in label_data:
            results.append({'error': 'Missing required fields', 'data': label_data})
            continue
        
        image_id = label_data['image_id']
        annotator_id = label_data['annotator_id']
        label = label_data['label']
        confidence = label_data.get('confidence', 1.0)
        
        labeling_system.add_label(image_id, annotator_id, label, confidence)
        aggregated = labeling_system.get_aggregated_label(image_id)
        
        results.append({
            'status': 'success',
            'image_id': image_id,
            'aggregated_label': aggregated
        })
    
    return jsonify({
        'status': 'success',
        'processed': len(results),
        'results': results
    })

